   869→// GetPreviousRelease returns the most recent release for a source that is not
   870→// the given version, ordered by created_at descending. Returns nil (no error)
   871→// if no previous release exists.
   872→func (s *PgStore) GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error) {
   873→	var rel models.Release
   874→	err := s.pool.QueryRow(ctx,
   875→		`SELECT id, source_id, version, COALESCE(raw_data,'{}'), released_at, created_at
   876→		 FROM releases
   877→		 WHERE source_id = $1 AND version != $2
   878→		 ORDER BY COALESCE(released_at, created_at) DESC
   879→		 LIMIT 1`, sourceID, beforeVersion,
   880→	).Scan(&rel.ID, &rel.SourceID, &rel.Version, &rel.RawData, &rel.ReleasedAt, &rel.CreatedAt)
   881→	if err != nil {
   882→		if err.Error() == "no rows in result set" {
   883→			return nil, nil
   884→		}
   885→		return nil, fmt.Errorf("get previous release: %w", err)
   886→	}
   887→	return &rel, nil
   888→}
