   890→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   891→// This follows the transactional outbox pattern for zero-loss guarantee.
   892→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   893→	tx, err := s.pool.Begin(ctx)
   894→	if err != nil {
   895→		return fmt.Errorf("begin tx: %w", err)
