   900→	err = tx.QueryRow(ctx,
   901→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   902→		 VALUES ($1, $2, $3, 'pending')
   903→		 RETURNING id`, projectID, trigger, version,
   904→	).Scan(&runID)
   905→	if err != nil {
   906→		return fmt.Errorf("insert agent run: %w", err)
   907→	}
