   909→	if s.river != nil {
   910→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   911→			AgentRunID: runID,
   912→			ProjectID:  projectID,
   913→			Version:    version,
   914→		}, nil)

