    51→
    52→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    53→// calls the API, and converts the response back to an LLMResponse.
    54→// Streaming is not implemented; the iterator always yields a single response.
    55→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    56→	return func(yield func(*model.LLMResponse, error) bool) {
    57→		resp, err := m.doRequest(ctx, req)
    58→		if err != nil {
