   205→// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   206→func convertContents(req *model.LLMRequest) []chatMessage {
   207→	var msgs []chatMessage
   208→
   209→	// System instruction.
   210→	if req.Config != nil && req.Config.SystemInstruction != nil {
   211→		var text string
   212→		for _, p := range req.Config.SystemInstruction.Parts {
   213→			if p.Text != "" {
   214→				text += p.Text
   215→			}
   216→		}
   217→		if text != "" {
   218→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   219→		}
   220→	}
   221→
   222→	// Conversation contents.
   223→	for _, c := range req.Contents {
   224→		role := mapRole(c.Role)
   225→
   226→		// Check each part: could be text, function_call, or function_response.
   227→		for _, p := range c.Parts {
   228→			switch {
   229→			case p.FunctionCall != nil:
   230→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   231→				msgs = append(msgs, chatMessage{
   232→					Role: "assistant",
   233→					ToolCalls: []toolCall{{
   234→						ID:   p.FunctionCall.ID,
   235→						Type: "function",
   236→						Function: functionCall{
   237→							Name:      p.FunctionCall.Name,
   238→							Arguments: string(argsJSON),
   239→						},
   240→					}},
   241→				})
   242→			case p.FunctionResponse != nil:
   243→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   244→				msgs = append(msgs, chatMessage{
   245→					Role:       "tool",
   246→					Content:    string(respJSON),
   247→					ToolCallID: p.FunctionResponse.ID,
   248→				})
   249→			case p.Text != "":
   250→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   251→			}
   252→		}
   253→	}
   254→
   255→	// Merge consecutive assistant messages with tool_calls.
   256→	msgs = mergeAssistantToolCalls(msgs)
   257→
   258→	return msgs
   259→}
   260→
   261→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   262→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   263→// one message rather than separate messages.
   264→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   265→	if len(msgs) == 0 {
   266→		return msgs
   267→	}
   268→	var merged []chatMessage
   269→	for _, msg := range msgs {
   270→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   271→			prev := &merged[len(merged)-1]
   272→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   273→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
