   295→
   296→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   297→func convertTools(req *model.LLMRequest) []chatTool {
   298→	if req.Config == nil || len(req.Config.Tools) == 0 {
   299→		return nil
   300→	}
   301→
   302→	var tools []chatTool
   303→	for _, t := range req.Config.Tools {
   304→		if t.GoogleSearch != nil {
   305→			continue
   306→		}
   307→		for _, fd := range t.FunctionDeclarations {
   308→			ct := chatTool{
   309→				Type: "function",
   310→				Function: chatFunction{
   311→					Name:        fd.Name,
   312→					Description: fd.Description,
   313→				},
   314→			}
   315→			if fd.Parameters != nil {
   316→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   317→			}
   318→			tools = append(tools, ct)
   319→		}
   320→	}
   321→	return tools
   322→}
   323→
   324→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   325→// the OpenAI function parameters format (JSON Schema).
   326→func schemaToMap(s *genai.Schema) map[string]any {
   327→	m := map[string]any{}
   328→	if s.Type != "" {
   329→		m["type"] = strings.ToLower(string(s.Type))
   330→	}
   331→	if s.Description != "" {
   332→		m["description"] = s.Description
   333→	}
   334→	if len(s.Enum) > 0 {
   335→		m["enum"] = s.Enum
   336→	}
   337→	if s.Items != nil {
   338→		m["items"] = schemaToMap(s.Items)
   339→	}
   340→	if len(s.Properties) > 0 {
   341→		props := map[string]any{}
   342→		for k, v := range s.Properties {
   343→			props[k] = schemaToMap(v)
   344→		}
   345→		m["properties"] = props
   346→	}
   347→	if len(s.Required) > 0 {
   348→		m["required"] = s.Required
   349→	}
   350→	return m
   351→}
   352→
   353→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   354→func convertResponse(resp *chatResponse) *model.LLMResponse {
   355→	llmResp := &model.LLMResponse{
   356→		TurnComplete: true,
   357→	}
   358→
   359→	if len(resp.Choices) == 0 {
   360→		llmResp.Content = genai.NewContentFromText("", "model")
   361→		return llmResp
   362→	}
   363→
   364→	choice := resp.Choices[0]
   365→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   366→
   367→	content := &genai.Content{Role: "model"}
   368→
   369→	// Text content.
   370→	if choice.Message.Content != "" {
   371→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   372→	}
   373→
   374→	// Tool calls.
   375→	for _, tc := range choice.Message.ToolCalls {
   376→		var args map[string]any
   377→		if tc.Function.Arguments != "" {
   378→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   379→		}
   380→		content.Parts = append(content.Parts, &genai.Part{
   381→			FunctionCall: &genai.FunctionCall{
   382→				ID:   tc.ID,
   383→				Name: tc.Function.Name,
   384→				Args: args,
   385→			},
   386→		})
   387→	}
   388→
   389→	llmResp.Content = content
   390→
   391→	if resp.Usage != nil {
   392→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   393→			PromptTokenCount:     resp.Usage.PromptTokens,
   394→			CandidatesTokenCount: resp.Usage.CompletionTokens,
   395→			TotalTokenCount:      resp.Usage.TotalTokens,
   396→		}
   397→	}
   398→
   399→	return llmResp
   400→}
   401→
   402→func mapRole(role string) string {
   403→	switch role {
   404→	case "model":
   405→		return "assistant"
   406→	default:
   407→		return role
   408→	}
   409→}
   410→
   411→func mapFinishReason(reason string) genai.FinishReason {
   412→	switch reason {
   413→	case "stop":
   414→		return genai.FinishReasonStop
   415→	case "length":
   416→		return genai.FinishReasonMaxTokens
   417→	case "tool_calls":
   418→		return genai.FinishReasonStop
   419→	case "content_filter":
   420→		return genai.FinishReasonSafety
   421→	default:
   422→		return genai.FinishReasonOther
   423→	}
   424→}
