   451→```go
   452→// convertInputs transforms ADK genai.Content messages into Responses API input items.
   453→// Returns the input items and extracted system instructions.
   454→func convertInputs(req *model.LLMRequest) ([]inputItem, string) {
   455→	var items []inputItem
   456→	var instructions string
   457→
   458→	// Extract system instruction separately (Responses API uses "instructions" field).
   459→	if req.Config != nil && req.Config.SystemInstruction != nil {
   460→		var text string
   461→		for _, p := range req.Config.SystemInstruction.Parts {
   462→			if p.Text != "" {
   463→				text += p.Text
   464→			}
   465→		}
   466→		instructions = text
   467→	}
   468→
   469→	// Conversation contents.
   470→	for _, c := range req.Contents {
   471→		role := mapRole(c.Role)
   472→
   473→		for _, p := range c.Parts {
   474→			switch {
   475→			case p.FunctionCall != nil:
   476→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   477→				items = append(items, inputItem{
   478→					Type:      "function_call",
   479→					CallID:    p.FunctionCall.ID,
   480→					Name:      p.FunctionCall.Name,
   481→					Arguments: string(argsJSON),
   482→				})
   483→			case p.FunctionResponse != nil:
   484→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   485→				items = append(items, inputItem{
   486→					Type:   "function_call_output",
   487→					CallID: p.FunctionResponse.ID,
   488→					Output: string(respJSON),
   489→				})
   490→			case p.Text != "":
   491→				items = append(items, inputItem{
   492→					Type:    "message",
   493→					Role:    role,
   494→					Content: p.Text,
   495→				})
   496→			}
   497→		}
   498→	}
   499→
   500→	return items, instructions
   501→}
   502→
   503→// webSearchConfig extracts web search parameters from the WebSearch tool
   504→// registered on the model. Returns nil if no WebSearch is configured.
   505→func (m *openaiModel) webSearchConfig() *WebSearch {
   506→	return m.wsConfig
   507→}
   508→
   509→// convertResponseTools transforms ADK genai.Tool definitions into Responses API tools.
   510→// If wsConfig is non-nil and a GoogleSearch marker is present, it emits a web_search
   511→// tool with the configured parameters.
   512→func convertResponseTools(req *model.LLMRequest, wsConfig *WebSearch) []responseTool {
   513→	if req.Config == nil || len(req.Config.Tools) == 0 {
   514→		return nil
   515→	}
   516→
   517→	var tools []responseTool
   518→	hasSearch := false
   519→
   520→	for _, t := range req.Config.Tools {
   521→		if t.GoogleSearch != nil {
   522→			hasSearch = true
   523→			continue
   524→		}
   525→		for _, fd := range t.FunctionDeclarations {
   526→			rt := responseTool{
   527→				Type:        "function",
   528→				Name:        fd.Name,
   529→				Description: fd.Description,
   530→			}
   531→			if fd.Parameters != nil {
   532→				rt.Parameters = schemaToMap(fd.Parameters)
   533→			}
   534→			tools = append(tools, rt)
   535→		}
   536→	}
   537→
   538→	if hasSearch {
   539→		wsTool := responseTool{Type: "web_search"}
   540→		if wsConfig != nil {
   541→			if wsConfig.SearchContextSize != "" {
   542→				wsTool.SearchContextSize = wsConfig.SearchContextSize
   543→			}
   544→			if len(wsConfig.AllowedDomains) > 0 {
   545→				wsTool.Filters = &searchFilters{
   546→					AllowedDomains: wsConfig.AllowedDomains,
   547→				}
   548→			}
   549→		}
   550→		tools = append(tools, wsTool)
   551→	}
   552→
   553→	return tools
   554→}
   555→
   556→// convertResponseOutput transforms a Responses API response into an ADK LLMResponse.
   557→func convertResponseOutput(resp *responsesResponse) *model.LLMResponse {
   558→	llmResp := &model.LLMResponse{
   559→		TurnComplete: true,
   560→	}
   561→
   562→	content := &genai.Content{Role: "model"}
   563→
   564→	for _, item := range resp.Output {
   565→		switch item.Type {
   566→		case "function_call":
   567→			var args map[string]any
   568→			if item.Arguments != "" {
   569→				_ = json.Unmarshal([]byte(item.Arguments), &args)
   570→			}
   571→			content.Parts = append(content.Parts, &genai.Part{
   572→				FunctionCall: &genai.FunctionCall{
   573→					ID:   item.CallID,
   574→					Name: item.Name,
   575→					Args: args,
   576→				},
   577→			})
   578→			llmResp.FinishReason = genai.FinishReasonStop
   579→
   580→		case "message":
   581→			for _, c := range item.Content {
   582→				if c.Text != "" {
   583→					content.Parts = append(content.Parts, &genai.Part{Text: c.Text})
   584→				}
   585→			}
   586→			llmResp.FinishReason = genai.FinishReasonStop
   587→
   588→		case "web_search_call":
   589→			// Informational; no ADK equivalent. Skip.
   590→		}
   591→	}
   592→
   593→	if len(content.Parts) == 0 {
   594→		content.Parts = append(content.Parts, &genai.Part{Text: ""})
   595→	}
   596→
   597→	llmResp.Content = content
   598→
   599→	if resp.Usage != nil {
   600→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   601→			PromptTokenCount:     resp.Usage.InputTokens,
   602→			CandidatesTokenCount: resp.Usage.OutputTokens,
   603→			TotalTokenCount:      resp.Usage.TotalTokens,
   604→		}
   605→	}
   606→
   607→	return llmResp
   608→}
   609→```
