   353→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   354→func convertResponse(resp *chatResponse) *model.LLMResponse {
   355→	llmResp := &model.LLMResponse{
   356→		TurnComplete: true,
   357→	}
   358→
   359→	if len(resp.Choices) == 0 {
