     7→	"fmt"
     8→	"io"
     9→	"iter"
    10→	"net/http"
    11→	"strings"
    12→
    13→	"google.golang.org/adk/model"
    14→	"google.golang.org/genai"
    15→)
    16→
    17→const defaultBaseURL = "https://api.openai.com/v1"
    18→
    19→// Config holds connection parameters for an OpenAI-compatible API.
    20→type Config struct {
    21→	APIKey  string
    22→	BaseURL string // defaults to https://api.openai.com/v1
    23→}
    24→
    25→// openaiModel implements model.LLM for OpenAI-compatible Responses APIs.
    26→type openaiModel struct {
    27→	name     string
    28→	apiKey   string
    29→	baseURL  string
    30→	client   *http.Client
    31→	wsConfig *WebSearch
    32→}
    33→
    34→// NewModel creates an OpenAI-backed model.LLM. wsConfig may be nil if web
    35→// search is not needed.
    36→func NewModel(_ context.Context, modelName string, cfg Config, wsConfig *WebSearch) (model.LLM, error) {
    37→	if cfg.APIKey == "" {
    38→		return nil, fmt.Errorf("openai: API key is required")
    39→	}
    40→	baseURL := cfg.BaseURL
    41→	if baseURL == "" {
    42→		baseURL = defaultBaseURL
    43→	}
    44→	return &openaiModel{
    45→		name:     modelName,
    46→		apiKey:   cfg.APIKey,
    47→		baseURL:  baseURL,
    48→		client:   &http.Client{},
    49→		wsConfig: wsConfig,
    50→	}, nil
    51→}
    52→
    53→func (m *openaiModel) Name() string { return m.name }
    54→
    55→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    56→// calls the API, and converts the response back to an LLMResponse.
    57→// Streaming is not implemented; the iterator always yields a single response.
    58→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    59→	return func(yield func(*model.LLMResponse, error) bool) {
    60→		resp, err := m.doRequest(ctx, req)
    61→		if err != nil {
    62→			yield(nil, err)
    63→			return
    64→		}
    65→		yield(resp, nil)
    66→	}
    67→}
    68→
    69→// Close is a no-op; the HTTP client has no persistent state.
    70→func (m *openaiModel) Close() {}
    71→
    72→// --- Responses API types ---
    73→
    74→type responsesRequest struct {
    75→	Model        string         `json:"model"`
    76→	Input        []inputItem    `json:"input"`
    77→	Instructions string         `json:"instructions,omitempty"`
    78→	Tools        []responseTool `json:"tools,omitempty"`
    79→	Temperature  *float32       `json:"temperature,omitempty"`
    80→	TopP         *float32       `json:"top_p,omitempty"`
    81→	MaxTokens    int32          `json:"max_output_tokens,omitempty"`
    82→	Store        bool           `json:"store"`
    83→}
    84→
    85→type inputItem struct {
    86→	Type      string `json:"type"`               // "message", "function_call", "function_call_output"
    87→	Role      string `json:"role,omitempty"`
    88→	Content   string `json:"content,omitempty"`
    89→	ID        string `json:"id,omitempty"`
    90→	CallID    string `json:"call_id,omitempty"`
    91→	Name      string `json:"name,omitempty"`
    92→	Arguments string `json:"arguments,omitempty"`
    93→	Output    string `json:"output,omitempty"`
    94→}
    95→
    96→type responseTool struct {
    97→	Type              string         `json:"type"` // "function" or "web_search"
    98→	Name              string         `json:"name,omitempty"`
    99→	Description       string         `json:"description,omitempty"`
   100→	Parameters        any            `json:"parameters,omitempty"`
   101→	SearchContextSize string         `json:"search_context_size,omitempty"`
   102→	UserLocation      any            `json:"user_location,omitempty"`
   103→	Filters           *searchFilters `json:"filters,omitempty"`
   104→}
   105→
   106→type searchFilters struct {
   107→	AllowedDomains []string `json:"allowed_domains,omitempty"`
   108→}
   109→
   110→type responsesResponse struct {
   111→	ID         string       `json:"id"`
   112→	Status     string       `json:"status"`
   113→	Output     []outputItem `json:"output"`
   114→	OutputText string       `json:"output_text"`
   115→	Usage      *respUsage   `json:"usage,omitempty"`
   116→	Error      *apiError    `json:"error,omitempty"`
   117→}
   118→
   119→type outputItem struct {
   120→	Type      string          `json:"type"` // "message", "function_call", "web_search_call"
   121→	ID        string          `json:"id,omitempty"`
   122→	Status    string          `json:"status,omitempty"`
   123→	CallID    string          `json:"call_id,omitempty"`
   124→	Name      string          `json:"name,omitempty"`
   125→	Arguments string          `json:"arguments,omitempty"`
   126→	Role      string          `json:"role,omitempty"`
   127→	Content   []outputContent `json:"content,omitempty"`
   128→}
   129→
   130→type outputContent struct {
   131→	Type        string       `json:"type"` // "output_text"
   132→	Text        string       `json:"text"`
   133→	Annotations []annotation `json:"annotations,omitempty"`
   134→}
   135→
   136→type annotation struct {
   137→	Type       string `json:"type"` // "url_citation"
   138→	URL        string `json:"url"`
   139→	Title      string `json:"title"`
   140→	StartIndex int    `json:"start_index"`
   141→	EndIndex   int    `json:"end_index"`
   142→}
   143→
   144→type respUsage struct {
   145→	InputTokens  int32 `json:"input_tokens"`
   146→	OutputTokens int32 `json:"output_tokens"`
   147→	TotalTokens  int32 `json:"total_tokens"`
   148→}
   149→
   150→type apiError struct {
   151→	Message string `json:"message"`
   152→	Type    string `json:"type"`
   153→	Code    string `json:"code"`
   154→}
   155→
   156→// --- request/response conversion ---
   157→
   158→func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   159→	items, instructions := convertInputs(req)
   160→	tools := convertResponseTools(req, m.wsConfig)
   161→
   162→	respReq := responsesRequest{
   163→		Model:        m.name,
   164→		Input:        items,
   165→		Instructions: instructions,
   166→		Tools:        tools,
   167→		Store:        false,
   168→	}
   169→
   170→	if req.Config != nil {
   171→		respReq.Temperature = req.Config.Temperature
   172→		respReq.TopP = req.Config.TopP
   173→		if req.Config.MaxOutputTokens > 0 {
   174→			respReq.MaxTokens = req.Config.MaxOutputTokens
   175→		}
   176→	}
   177→
   178→	body, err := json.Marshal(respReq)
   179→	if err != nil {
   180→		return nil, fmt.Errorf("openai: marshal request: %w", err)
   181→	}
   182→
   183→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/responses", bytes.NewReader(body))
   184→	if err != nil {
   185→		return nil, fmt.Errorf("openai: create http request: %w", err)
   186→	}
   187→	httpReq.Header.Set("Content-Type", "application/json")
   188→	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   189→
   190→	httpResp, err := m.client.Do(httpReq)
   191→	if err != nil {
   192→		return nil, fmt.Errorf("openai: http request: %w", err)
   193→	}
   194→	defer httpResp.Body.Close()
   195→
   196→	respBody, err := io.ReadAll(httpResp.Body)
   197→	if err != nil {
   198→		return nil, fmt.Errorf("openai: read response: %w", err)
   199→	}
   200→
   201→	if httpResp.StatusCode != http.StatusOK {
   202→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   203→	}
   204→
   205→	var respOut responsesResponse
   206→	if err := json.Unmarshal(respBody, &respOut); err != nil {
   207→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   208→	}
   209→
   210→	if respOut.Error != nil {
   211→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   212→			respOut.Error.Message, respOut.Error.Type, respOut.Error.Code)
   213→	}
   214→
   215→	return convertResponseOutput(&respOut), nil
   216→}
   217→
   218→// convertInputs transforms ADK Contents into Responses API input items and
   219→// extracts the system instruction as a separate instructions string.
   220→func convertInputs(req *model.LLMRequest) ([]inputItem, string) {
   221→	var items []inputItem
   222→	var instructions string
   223→
   224→	// System instruction.
   225→	if req.Config != nil && req.Config.SystemInstruction != nil {
   226→		var text string
   227→		for _, p := range req.Config.SystemInstruction.Parts {
   228→			if p.Text != "" {
   229→				text += p.Text
   230→			}
   231→		}
   232→		instructions = text
   233→	}
   234→
   235→	// Conversation contents.
   236→	for _, c := range req.Contents {
   237→		for _, p := range c.Parts {
   238→			switch {
   239→			case p.FunctionCall != nil:
   240→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   241→				items = append(items, inputItem{
   242→					Type:      "function_call",
   243→					CallID:    p.FunctionCall.ID,
   244→					Name:      p.FunctionCall.Name,
   245→					Arguments: string(argsJSON),
   246→				})
   247→			case p.FunctionResponse != nil:
   248→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   249→				items = append(items, inputItem{
   250→					Type:   "function_call_output",
   251→					CallID: p.FunctionResponse.ID,
   252→					Output: string(respJSON),
   253→				})
   254→			case p.Text != "":
   255→				items = append(items, inputItem{
   256→					Type:    "message",
   257→					Role:    mapRole(c.Role),
   258→					Content: p.Text,
   259→				})
   260→			}
   261→		}
   262→	}
   263→
   264→	return items, instructions
   265→}
   266→
   267→// convertResponseTools transforms ADK tools to Responses API flat format.
   268→// Function tools become {type: "function", name, description, parameters}.
   269→// If a GoogleSearch marker is present, a {type: "web_search"} tool is added
   270→// using wsConfig for search_context_size and allowed_domains.
   271→func convertResponseTools(req *model.LLMRequest, wsConfig *WebSearch) []responseTool {
   272→	if req.Config == nil || len(req.Config.Tools) == 0 {
   273→		return nil
   274→	}
   275→
   276→	var tools []responseTool
   277→	hasSearch := false
   278→
   279→	for _, t := range req.Config.Tools {
   280→		if t.GoogleSearch != nil {
   281→			hasSearch = true
   282→			continue
   283→		}
   284→		for _, fd := range t.FunctionDeclarations {
   285→			rt := responseTool{
   286→				Type:        "function",
   287→				Name:        fd.Name,
   288→				Description: fd.Description,
   289→			}
   290→			if fd.Parameters != nil {
   291→				rt.Parameters = schemaToMap(fd.Parameters)
   292→			}
   293→			tools = append(tools, rt)
   294→		}
   295→	}
   296→
   297→	if hasSearch {
   298→		wsTool := responseTool{Type: "web_search"}
   299→		if wsConfig != nil {
   300→			wsTool.SearchContextSize = wsConfig.SearchContextSize
   301→			if len(wsConfig.AllowedDomains) > 0 {
   302→				wsTool.Filters = &searchFilters{
   303→					AllowedDomains: wsConfig.AllowedDomains,
   304→				}
   305→			}
   306→		}
   307→		tools = append(tools, wsTool)
   308→	}
   309→
   310→	return tools
   311→}
   312→
   313→// convertResponseOutput transforms a Responses API response into an ADK LLMResponse.
   314→func convertResponseOutput(resp *responsesResponse) *model.LLMResponse {
   315→	llmResp := &model.LLMResponse{
   316→		TurnComplete: true,
   317→	}
   318→
   319→	content := &genai.Content{Role: "model"}
   320→
   321→	for _, item := range resp.Output {
   322→		switch item.Type {
   323→		case "function_call":
   324→			var args map[string]any
   325→			if item.Arguments != "" {
   326→				_ = json.Unmarshal([]byte(item.Arguments), &args)
   327→			}
   328→			content.Parts = append(content.Parts, &genai.Part{
   329→				FunctionCall: &genai.FunctionCall{
   330→					ID:   item.CallID,
   331→					Name: item.Name,
   332→					Args: args,
   333→				},
   334→			})
   335→		case "message":
   336→			for _, c := range item.Content {
   337→				if c.Text != "" {
   338→					content.Parts = append(content.Parts, &genai.Part{Text: c.Text})
   339→				}
   340→			}
   341→		case "web_search_call":
   342→			// Skipped — handled internally by the API.
   343→		}
   344→	}
   345→
   346→	if len(content.Parts) == 0 {
   347→		content.Parts = append(content.Parts, &genai.Part{Text: ""})
   348→	}
   349→
   350→	llmResp.Content = content
   351→
   352→	if resp.Usage != nil {
   353→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   354→			PromptTokenCount:     resp.Usage.InputTokens,
   355→			CandidatesTokenCount: resp.Usage.OutputTokens,
   356→			TotalTokenCount:      resp.Usage.TotalTokens,
   357→		}
   358→	}
   359→
   360→	return llmResp
   361→}
   362→
   363→func mapRole(role string) string {
   364→	switch role {
   365→	case "model":
   366→		return "assistant"
   367→	default:
   368→		return role
   369→	}
   370→}
   371→
   372→func mapFinishReason(reason string) genai.FinishReason {
   373→	switch reason {
   374→	case "stop":
   375→		return genai.FinishReasonStop
   376→	case "length":
   377→		return genai.FinishReasonMaxTokens
   378→	case "tool_calls":
   379→		return genai.FinishReasonStop
   380→	case "content_filter":
   381→		return genai.FinishReasonSafety
   382→	default:
   383→		return genai.FinishReasonOther
   384→	}
   385→}
   386→

