    }

    var funcTool, searchTool *responseTool
    for i := range tools {
        switch tools[i].Type {
        case "function":
            funcTool = &tools[i]
        case "web_search":
            searchTool = &tools[i]
        }
    }

    if funcTool == nil || funcTool.Name != "get_releases" {
        t.Errorf("missing or wrong function tool")
    }
    if searchTool == nil {
        t.Fatal("no web_search tool found")
