    55→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    56→// calls the API, and converts the response back to an LLMResponse.
    57→// Streaming is not implemented; the iterator always yields a single response.
    58→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    59→	return func(yield func(*model.LLMResponse, error) bool) {
    60→		resp, err := m.doRequest(ctx, req)
    61→		if err != nil {
    62→			yield(nil, err)
    63→			return
    64→		}
    65→		yield(resp, nil)
    66→	}
    67→}
    68→
    69→// Close is a no-op; the HTTP client has no persistent state.
    70→func (m *openaiModel) Close() {}
