   218→// convertInputs transforms ADK Contents into Responses API input items and
   219→// extracts the system instruction as a separate instructions string.
   220→func convertInputs(req *model.LLMRequest) ([]inputItem, string) {
   221→	var items []inputItem
   222→	var instructions string
   223→
   224→	// System instruction.
   225→	if req.Config != nil && req.Config.SystemInstruction != nil {
   226→		var text string
   227→		for _, p := range req.Config.SystemInstruction.Parts {
   228→			if p.Text != "" {
   229→				text += p.Text
   230→			}
   231→		}
   232→		instructions = text
   233→	}
   234→
   235→	// Conversation contents.
   236→	for _, c := range req.Contents {
   237→		for _, p := range c.Parts {
   238→			switch {
   239→			case p.FunctionCall != nil:
   240→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   241→				items = append(items, inputItem{
   242→					Type:      "function_call",
   243→					CallID:    p.FunctionCall.ID,
   244→					Name:      p.FunctionCall.Name,
   245→					Arguments: string(argsJSON),
   246→				})
   247→			case p.FunctionResponse != nil:
   248→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   249→				items = append(items, inputItem{
   250→					Type:   "function_call_output",
   251→					CallID: p.FunctionResponse.ID,
   252→					Output: string(respJSON),
   253→				})
   254→			case p.Text != "":
   255→				items = append(items, inputItem{
   256→					Type:    "message",
   257→					Role:    mapRole(c.Role),
   258→					Content: p.Text,
   259→				})
   260→			}
   261→		}
   262→	}
   263→
   264→	return items, instructions
   265→}
   266→
   267→// convertResponseTools transforms ADK tools to Responses API flat format.
   268→// Function tools become {type: "function", name, description, parameters}.
   269→// If a GoogleSearch marker is present, a {type: "web_search"} tool is added
   270→// using wsConfig for search_context_size and allowed_domains.
   271→func convertResponseTools(req *model.LLMRequest, wsConfig *WebSearch) []responseTool {
   272→	if req.Config == nil || len(req.Config.Tools) == 0 {
   273→		return nil
   274→	}
   275→
   276→	var tools []responseTool
   277→	hasSearch := false
   278→
   279→	for _, t := range req.Config.Tools {
   280→		if t.GoogleSearch != nil {
   281→			hasSearch = true
   282→			continue
   283→		}
   284→		for _, fd := range t.FunctionDeclarations {
   285→			rt := responseTool{
   286→				Type:        "function",
   287→				Name:        fd.Name,
   288→				Description: fd.Description,
   289→			}
   290→			if fd.Parameters != nil {
   291→				rt.Parameters = schemaToMap(fd.Parameters)
   292→			}
   293→			tools = append(tools, rt)
   294→		}
   295→	}
   296→
   297→	if hasSearch {
   298→		wsTool := responseTool{Type: "web_search"}
   299→		if wsConfig != nil {
   300→			wsTool.SearchContextSize = wsConfig.SearchContextSize
   301→			if len(wsConfig.AllowedDomains) > 0 {
   302→				wsTool.Filters = &searchFilters{
   303→					AllowedDomains: wsConfig.AllowedDomains,
   304→				}
   305→			}
   306→		}
   307→		tools = append(tools, wsTool)
   308→	}
   309→
   310→	return tools
   311→}
   312→
   313→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   314→// the OpenAI function parameters format (JSON Schema).
   315→func schemaToMap(s *genai.Schema) map[string]any {
   316→	m := map[string]any{}
   317→	if s.Type != "" {
   318→		m["type"] = strings.ToLower(string(s.Type))
   319→	}
   320→	if s.Description != "" {
   321→		m["description"] = s.Description
   322→	}
   323→	if len(s.Enum) > 0 {
   324→		m["enum"] = s.Enum
   325→	}
   326→	if s.Items != nil {
   327→		m["items"] = schemaToMap(s.Items)
   328→	}
   329→	if len(s.Properties) > 0 {
   330→		props := map[string]any{}
   331→		for k, v := range s.Properties {
   332→			props[k] = schemaToMap(v)
   333→		}
   334→		m["properties"] = props
   335→	}
   336→	if len(s.Required) > 0 {
   337→		m["required"] = s.Required
   338→	}
   339→	return m
   340→}
   341→
   342→// convertResponseOutput transforms a Responses API response into an ADK LLMResponse.
   343→func convertResponseOutput(resp *responsesResponse) *model.LLMResponse {
   344→	llmResp := &model.LLMResponse{
   345→		TurnComplete: true,
   346→	}
   347→
   348→	content := &genai.Content{Role: "model"}
   349→
   350→	for _, item := range resp.Output {
   351→		switch item.Type {
   352→		case "function_call":
   353→			var args map[string]any
   354→			if item.Arguments != "" {
   355→				_ = json.Unmarshal([]byte(item.Arguments), &args)
   356→			}
   357→			content.Parts = append(content.Parts, &genai.Part{
   358→				FunctionCall: &genai.FunctionCall{
   359→					ID:   item.CallID,
   360→					Name: item.Name,
   361→					Args: args,
   362→				},
   363→			})
   364→		case "message":
   365→			for _, c := range item.Content {
   366→				if c.Text != "" {
   367→					content.Parts = append(content.Parts, &genai.Part{Text: c.Text})
   368→				}
   369→			}
   370→		case "web_search_call":
   371→			// Skipped — handled internally by the API.
   372→		}
   373→	}
   374→
   375→	if len(content.Parts) == 0 {
   376→		content.Parts = append(content.Parts, &genai.Part{Text: ""})
   377→	}
   378→
   379→	llmResp.Content = content
   380→
   381→	if resp.Usage != nil {
   382→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   383→			PromptTokenCount:     resp.Usage.InputTokens,
   384→			CandidatesTokenCount: resp.Usage.OutputTokens,
   385→			TotalTokenCount:      resp.Usage.TotalTokens,
   386→		}
   387→	}
   388→
   389→	return llmResp
   390→}
