   195→
   196→	respBody, err := io.ReadAll(httpResp.Body)
   197→	if err != nil {
   198→		return nil, fmt.Errorf("openai: read response: %w", err)
   199→	}
   200→
   201→	if httpResp.StatusCode != http.StatusOK {
   202→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   203→	}
   204→
   205→	var respOut responsesResponse
   206→	if err := json.Unmarshal(respBody, &respOut); err != nil {
   207→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   208→	}
   209→
   210→	if respOut.Error != nil {
   211→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   212→			respOut.Error.Message, respOut.Error.Type, respOut.Error.Code)
   213→	}
   214→
   215→	return convertResponseOutput(&respOut), nil
   216→}
