   218→// convertInputs transforms ADK Contents into Responses API input items and
   219→// extracts the system instruction as a separate instructions string.
   220→func convertInputs(req *model.LLMRequest) ([]inputItem, string) {
   221→	var items []inputItem
   222→	var instructions string
   223→
   224→	// System instruction.
   225→	if req.Config != nil && req.Config.SystemInstruction != nil {
   226→		var text string
   227→		for _, p := range req.Config.SystemInstruction.Parts {
   228→			if p.Text != "" {
   229→				text += p.Text
   230→			}
   231→		}
   232→		instructions = text
   233→	}
   234→
   235→	// Conversation contents.
   236→	for _, c := range req.Contents {
   237→		for _, p := range c.Parts {
   238→			switch {
   239→			case p.FunctionCall != nil:
   240→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   241→				items = append(items, inputItem{
   242→					Type:      "function_call",
   243→					CallID:    p.FunctionCall.ID,
   244→					Name:      p.FunctionCall.Name,
   245→					Arguments: string(argsJSON),
   246→				})
   247→			case p.FunctionResponse != nil:
   248→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   249→				items = append(items, inputItem{
   250→					Type:   "function_call_output",
   251→					CallID: p.FunctionResponse.ID,
   252→					Output: string(respJSON),
   253→				})
   254→			case p.Text != "":
   255→				items = append(items, inputItem{
   256→					Type:    "message",
   257→					Role:    mapRole(c.Role),
   258→					Content: p.Text,
   259→				})
   260→			}
   261→		}
   262→	}
   263→
   264→	return items, instructions
   265→}
